311	// CapabilitiesViaService returns HarnessCapabilities for the named harness by
312	// querying the service's ListHarnesses and (best-effort) the harness registry.
313	// It is the production replacement for Runner.Capabilities.
314	func CapabilitiesViaService(ctx context.Context, workDir, harnessName string) (*HarnessCapabilities, error) {
315		if ctx == nil {
316			ctx = context.Background()
317		}
318		svc, err := NewServiceFromWorkDir(workDir)
319		if err != nil {
320			return nil, fmt.Errorf("agent: build service: %w", err)
321		}
322		infos, err := svc.ListHarnesses(ctx)
323		if err != nil {
324			return nil, fmt.Errorf("agent: list harnesses: %w", err)
325		}
326		var info *agentlib.HarnessInfo
327		for i := range infos {
328			if infos[i].Name == harnessName {
329				info = &infos[i]
330				break
331			}
332		}
333		if info == nil {
334			return nil, fmt.Errorf("agent: unknown harness: %s", harnessName)
335		}
336	
337		// Pull binary and reasoning-level metadata from the local registry — the
338		// service does not expose these directly today.
339		registry := newHarnessRegistry()
340		harness, _ := registry.Get(harnessName)
341	
342		caps := &HarnessCapabilities{
343			Harness:             info.Name,
344			Available:           info.Available,
345			Binary:              harness.Binary,
346			Path:                info.Path,
347			Surface:             harness.Surface,
348			CostClass:           info.CostClass,
349			IsLocal:             info.IsLocal,
350			ExactPinSupport:     info.ExactPinSupport,
351			SupportsEffort:      len(info.SupportedReasoning) > 0 || harness.EffortFlag != "",
352			SupportsPermissions: len(info.SupportedPermissions) > 0 || len(harness.PermissionArgs) > 0,
353		}
354		if len(info.SupportedReasoning) > 0 {
355			caps.ReasoningLevels = append([]string{}, info.SupportedReasoning...)
356		} else if len(harness.ReasoningLevels) > 0 {
357			caps.ReasoningLevels = append([]string{}, harness.ReasoningLevels...)
358		}
359	
360		if harness.DefaultModel != "" {
361			caps.Model = harness.DefaultModel
362			caps.Models = []string{harness.DefaultModel}
363		}
364	
365		return caps, nil
366	}
