368	// TestProviderConnectivityViaService runs a HealthCheck against the named
369	// harness and translates the result into a ProviderStatus. It is the
370	// production replacement for Runner.TestProviderConnectivity.
371	func TestProviderConnectivityViaService(ctx context.Context, workDir, harnessName string, timeout time.Duration) ProviderStatus {
372		status := ProviderStatus{Reachable: false}
373		if ctx == nil {
374			ctx = context.Background()
375		}
376		if harnessName == "virtual" || harnessName == "agent" {
377			status.Reachable = true
378			status.CreditsOK = true
379			return status
380		}
381		svc, err := NewServiceFromWorkDir(workDir)
382		if err != nil {
383			status.Error = err.Error()
384			return status
385		}
386		if timeout > 0 {
387			var cancel context.CancelFunc
388			ctx, cancel = context.WithTimeout(ctx, timeout)
389			defer cancel()
390		}
391		if err := svc.HealthCheck(ctx, agentlib.HealthTarget{Type: "harness", Name: harnessName}); err != nil {
392			errStr := strings.ToLower(err.Error())
393			status.Error = err.Error()
394			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
395				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
396				status.CreditsOK = false
397			}
398			return status
399		}
400		status.Reachable = true
401		status.CreditsOK = true
402		return status
403	}
