405	// ValidateForExecuteLoopViaService is the production replacement for
406	// Runner.ValidateForExecuteLoop. When harness is empty it is a no-op (routing
407	// will pick at claim time). When harness is specified it confirms the harness
408	// exists in the service registry and (when model is set) attempts a
409	// ResolveRoute pre-flight.
410	func ValidateForExecuteLoopViaService(ctx context.Context, workDir, harnessName, model, provider, modelRef string) error {
411		if harnessName == "" {
412			return nil
413		}
414		if ctx == nil {
415			ctx = context.Background()
416		}
417		svc, err := NewServiceFromWorkDir(workDir)
418		if err != nil {
419			return fmt.Errorf("agent: build service: %w", err)
420		}
421		infos, err := svc.ListHarnesses(ctx)
422		if err != nil {
423			return fmt.Errorf("agent: list harnesses: %w", err)
424		}
425		found := false
426		for _, info := range infos {
427			if info.Name == harnessName {
428				found = true
429				if !info.Available {
430					return fmt.Errorf("agent: harness %s not available", harnessName)
431				}
432				break
433			}
434		}
435		if !found {
436			return fmt.Errorf("agent: unknown harness: %s", harnessName)
437		}
438	
439		// Pre-flight orphan-model check via ResolveRoute. Only meaningful when a
440		// model is provided and provider/model-ref are not set.
441		if model != "" && provider == "" && modelRef == "" && harnessName == "agent" {
442			if _, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{
443				Model:    model,
444				Harness:  harnessName,
445				ModelRef: modelRef,
446				Provider: provider,
447			}); err != nil {
448				return fmt.Errorf("agent: model %q is not routable: %w", model, err)
449			}
450		}
451		return nil
452	}
