454	// ValidateEffortForRunViaService rejects effort requests that no currently
455	// available harness can satisfy. `ddx agent run` passes effort through to the
456	// service rather than resolving a route locally, but the command still needs a
457	// fast failure for obviously impossible combinations so operators get a useful
458	// error instead of a silent success path.
459	func ValidateEffortForRunViaService(ctx context.Context, workDir, profile, effort string) error {
460		if effort == "" {
461			return nil
462		}
463		if ctx == nil {
464			ctx = context.Background()
465		}
466		svc, err := NewServiceFromWorkDir(workDir)
467		if err != nil {
468			return fmt.Errorf("agent: build service: %w", err)
469		}
470		infos, err := svc.ListHarnesses(ctx)
471		if err != nil {
472			return fmt.Errorf("agent: list harnesses: %w", err)
473		}
474		registry := newHarnessRegistry()
475		for _, info := range infos {
476			if !info.Available {
477				continue
478			}
479			if harness, ok := registry.Get(info.Name); ok && harness.EffortFlag != "" {
480				return nil
481			}
482		}
483		if profile == "" {
484			return fmt.Errorf("agent: no selected provider candidate satisfies effort %q", effort)
485		}
486		return fmt.Errorf("agent: no selected provider candidate satisfies profile %q and effort %q", profile, effort)
487	}
