645			"wait_ms":     info.Wait.Milliseconds(),
646			"source":      info.Source,
647			"elapsed_ms":  info.Elapsed.Milliseconds(),
648			"over_budget": info.OverBudget,
649		}
650		if info.Result != nil {
651			if info.Result.Harness != "" {
652				body["harness"] = info.Result.Harness
653			}
654			if info.Result.Provider != "" {
