663			return
664		}
665		summary := fmt.Sprintf("attempt=%d wait=%s source=%s", info.Attempt, info.Wait.Round(time.Millisecond), info.Source)
666		if info.OverBudget {
667			summary = "budget exhausted: " + RateLimitBudgetExhaustedReason
668		}
